comments.body:
The following patch fixes the upper issue. What it does is to query if each "short flag" is actually in the flag set. If one or more is not in the set, the string will be left untouched and passed back to further parsing, so that something like `podman run -itrxwerewr` will yield a `flag provided but not defined: -itrxwerewr`.

Do you have feedback before proposing the fix upstream?

```patch
diff --git a/vendor/github.com/urfave/cli/command.go b/vendor/github.com/urfave/cli/command.go
index 66a58b5a8954..a21a7621153f 100644
--- a/vendor/github.com/urfave/cli/command.go
+++ b/vendor/github.com/urfave/cli/command.go
@@ -182,7 +182,7 @@ func (c *Command) parseFlags(args Args) (*flag.FlagSet, error) {
 	}

 	if c.UseShortOptionHandling {
-		args = translateShortOptions(args)
+		args = translateShortOptions(set, args)
 	}

 	if !c.SkipArgReorder {
@@ -231,11 +231,25 @@ func reorderArgs(args []string) []string {
 	return append(flags, nonflags...)
 }

-func translateShortOptions(flagArgs Args) []string {
+func translateShortOptions(set *flag.FlagSet, flagArgs Args) []string {
+	allCharsFlags := func (s string) bool {
+		for i := range s {
+			f := set.Lookup(string(s[i]))
+			if f == nil {
+				return false
+			}
+		}
+		return true
+	}
+
 	// separate combined flags
 	var flagArgsSeparated []string
 	for _, flagArg := range flagArgs {
 		if strings.HasPrefix(flagArg, "-") && strings.HasPrefix(flagArg, "--") == false && len(flagArg) > 2 {
+			if !allCharsFlags(flagArg[1:]) {
+				flagArgsSeparated = append(flagArgsSeparated, flagArg)
+				continue
+			}
 			for _, flagChar := range flagArg[1:] {
 				flagArgsSeparated = append(flagArgsSeparated, "-"+string(flagChar))
 			}
@@ -243,6 +257,7 @@ func translateShortOptions(flagArgs Args) []string {
 			flagArgsSeparated = append(flagArgsSeparated, flagArg)
 		}
 	}
+
 	return flagArgsSeparated
 }

```
